#nullable enable // autogenerated

using MVZ2.Vanilla.Detections;
using MVZ2.Vanilla.Entities;
using PVZEngine.Collisions;
using PVZEngine.Entities;
using UnityEngine;

namespace MVZ2.GameContent.Detections
{
    public class LockedChestDetector : Detector
    {
        public LockedChestDetector(int mode, bool canDetectInvisible = false)
        {
            this.mode = mode;
            this.canDetectInvisible = canDetectInvisible;
        }
        protected override Bounds GetDetectionBounds(Entity self)
        {
            var source = self.Position;
            float sizeX = 0;
            float sizeY = 0;
            float sizeZ = 0;
            float centerX = source.x;
            float centerY = source.y;
            float centerZ = source.z;
            switch (mode)
            {
                case MODE_SMASH:
                    {
                        sizeX = 200;
                        sizeY = 40;
                        sizeZ = 200;
                        centerX = source.x;
                        centerZ = source.z;
                        centerY = source.y + 20;
                    }
                    break;
                case MODE_CAMERA:
                    {
                        sizeX = 160;
                        sizeY = 800;
                        sizeZ = 240;
                        centerX = source.x + self.GetFacingX() * 240;
                        centerZ = source.z;
                        centerY = self.Level.GetGroundY(centerX, centerZ);
                    }
                    break;
                default:
                    {
                        sizeX = 240;
                        sizeY = 64;
                        sizeZ = 40;
                        centerX = source.x + sizeX * 0.5f * self.GetFacingX();
                        centerY = source.y + sizeY * 0.5f;
                        centerZ = source.z;
                    }
                    break;
            }
            return new Bounds(new Vector3(centerX, centerY, centerZ), new Vector3(sizeX, sizeY, sizeZ));
        }
        protected override bool ValidateCollider(DetectionParams param, IEntityCollider collider)
        {
            switch (mode)
            {
                case MODE_CAMERA:
                    {
                        var target = collider.Entity;
                        if (!target.CanDeactive())
                            return false;
                        if (target.IsAIFrozen())
                            return false;
                    }
                    break;

                case MODE_SMASH:
                    {
                        var center = param.entity.Position;
                        center += Vector3.up * 20;
                        float sizeX = 200;
                        float sizeY = 40;
                        float sizeZ = 40;
                        if (!collider.CheckBox(center, new Vector3(sizeX, sizeY, sizeZ)) && !collider.CheckBox(center, new Vector3(sizeZ, sizeY, sizeX)))
                            return false;
                    }
                    break;
            }
            return base.ValidateCollider(param, collider);
        }
        private int mode;
        public const int MODE_CAMERA = 0;
        public const int MODE_SMASH = 1;
    }
}
